local({
  merged_data <- merged_data %>%
    arrange(Date) %>%
    mutate(
      spx_return = (SPX_Close / lag(SPX_Close)) - 1,
      btc_return = (BITCOIN_Close / lag(BITCOIN_Close)) - 1
    )
  assign("merged_data", merged_data, envir = .GlobalEnv)
  rm(merged_data)   # clean up the temporary copy inside the block
})

local({
  merged_data <- merged_data %>%
    pivot_longer(
      cols = c(spx_return, btc_return),
      names_to = "Asset",
      values_to = "Return"
    )
  assign("merged_data", merged_data, envir = .GlobalEnv)
  rm(merged_data)   # clean up the temporary copy inside the block
})

local({
  # Verify the long‑format data exists
  if (!exists("merged_data")) {
    stop("merged_data not found – cannot create the plot.")
  }

  # Create the expected data frame name
  returns_long <- merged_data
  assign("returns_long", returns_long, envir = .GlobalEnv)

  # Ensure Date is a Date object
  if (!inherits(returns_long$Date, "Date")) {
    returns_long$Date <- as.Date(returns_long$Date)
  }

  # Plot the daily returns
  p <- ggplot(returns_long, aes(x = Date, y = Return, colour = Asset)) +
    geom_line() +
    labs(
      title = "Daily Returns: S&P 500 vs Bitcoin",
      x = "Date",
      y = "Return"
    ) +
    theme_minimal()
  print(p)
})

